PRAGMA foreign_keys=ON;
CREATE TABLE organizations(id TEXT PRIMARY KEY,name TEXT NOT NULL,fictional INTEGER NOT NULL DEFAULT 1);
CREATE TABLE teams(id TEXT PRIMARY KEY,organization_id TEXT REFERENCES organizations(id),name TEXT NOT NULL);
CREATE TABLE participants(id TEXT PRIMARY KEY,organization_id TEXT REFERENCES organizations(id),team_id TEXT REFERENCES teams(id),name TEXT,role TEXT,location TEXT,completeness REAL DEFAULT 1);
CREATE TABLE threads(id TEXT PRIMARY KEY,subject TEXT,reconstruction_confidence REAL,created_at TEXT NOT NULL);
CREATE TABLE messages(id TEXT PRIMARY KEY,thread_id TEXT NOT NULL REFERENCES threads(id) ON DELETE CASCADE,source_type TEXT NOT NULL,source_system TEXT NOT NULL,sender_id TEXT REFERENCES participants(id),sent_at TEXT NOT NULL,language TEXT NOT NULL,content TEXT NOT NULL,translated_content TEXT,reply_to_message_id TEXT REFERENCES messages(id));
CREATE TABLE message_participants(message_id TEXT REFERENCES messages(id) ON DELETE CASCADE,participant_id TEXT REFERENCES participants(id),role TEXT NOT NULL,PRIMARY KEY(message_id,participant_id,role));
CREATE TABLE entities(id TEXT PRIMARY KEY,type TEXT NOT NULL,name TEXT NOT NULL); CREATE TABLE entity_aliases(id TEXT PRIMARY KEY,entity_id TEXT REFERENCES entities(id),alias TEXT NOT NULL);
CREATE TABLE relationships(id TEXT PRIMARY KEY,source_entity_id TEXT REFERENCES entities(id),target_entity_id TEXT REFERENCES entities(id),type TEXT NOT NULL,confidence REAL,source_message_id TEXT REFERENCES messages(id));
CREATE TABLE events(id TEXT PRIMARY KEY,entity_id TEXT REFERENCES entities(id),type TEXT,occurred_at TEXT,source_message_id TEXT REFERENCES messages(id));
CREATE TABLE business_signals(id TEXT PRIMARY KEY,type TEXT,title TEXT,description TEXT,first_observed_at TEXT,last_observed_at TEXT,confidence REAL,extraction_mode TEXT,review_status TEXT);
CREATE TABLE signal_evidence(signal_id TEXT REFERENCES business_signals(id),message_id TEXT REFERENCES messages(id),PRIMARY KEY(signal_id,message_id));
CREATE TABLE claims(id TEXT PRIMARY KEY,subject_entity_id TEXT REFERENCES entities(id),predicate TEXT,object_value TEXT,claimant_participant_id TEXT REFERENCES participants(id),confidence REAL,stance TEXT,verification_status TEXT); CREATE TABLE claim_evidence(claim_id TEXT REFERENCES claims(id),message_id TEXT REFERENCES messages(id),PRIMARY KEY(claim_id,message_id));
CREATE TABLE contradictions(id TEXT PRIMARY KEY,confidence REAL,explanation TEXT,missing_evidence TEXT,resolution_question TEXT); CREATE TABLE repeated_problem_clusters(id TEXT PRIMARY KEY,title TEXT,occurrences INTEGER,first_seen TEXT,last_seen TEXT,trend TEXT,owner_id TEXT); CREATE TABLE abandoned_ideas(id TEXT PRIMARY KEY,proposal_signal_id TEXT REFERENCES business_signals(id),stopping_reason TEXT,reconsideration_score REAL); CREATE TABLE capabilities(id TEXT PRIMARY KEY,signal_id TEXT REFERENCES business_signals(id),maturity TEXT,reusability TEXT,confidence REAL,validation_status TEXT);
CREATE TABLE opportunities(id TEXT PRIMARY KEY,title TEXT,status TEXT,overall_score REAL,uncertainty REAL,data_json TEXT); CREATE TABLE opportunity_evidence(opportunity_id TEXT REFERENCES opportunities(id),signal_id TEXT REFERENCES business_signals(id),PRIMARY KEY(opportunity_id,signal_id)); CREATE TABLE validation_questions(id TEXT PRIMARY KEY,opportunity_id TEXT REFERENCES opportunities(id),question TEXT,type TEXT); CREATE TABLE validation_answers(id TEXT PRIMARY KEY,question_id TEXT REFERENCES validation_questions(id),participant_id TEXT REFERENCES participants(id),answer TEXT,evidence_type TEXT,created_at TEXT); CREATE TABLE experiments(id TEXT PRIMARY KEY,opportunity_id TEXT REFERENCES opportunities(id),status TEXT,data_json TEXT); CREATE TABLE outcomes(id TEXT PRIMARY KEY,experiment_id TEXT REFERENCES experiments(id),occurred_at TEXT,result TEXT,evidence TEXT,lesson TEXT); CREATE TABLE learning_records(id TEXT PRIMARY KEY,source_outcome_id TEXT REFERENCES outcomes(id),lesson TEXT,affected_pattern TEXT,previous_weight REAL,new_weight REAL,explanation TEXT,human_approved INTEGER DEFAULT 0,created_at TEXT); CREATE TABLE pipeline_runs(id TEXT PRIMARY KEY,mode TEXT,status TEXT,started_at TEXT,completed_at TEXT,error_code TEXT); CREATE TABLE application_settings(key TEXT PRIMARY KEY,value TEXT NOT NULL);
